arguments.command:
# Check what section the SGen worker addresses fall in
aarch64-linux-gnu-objdump -h /tmp/symbols/libmonosgen-2.0.so.dbg | awk '
/^[ ]*[0-9]+/ {
    name=$2; size=strtonum("0x"$3); vma=strtonum("0x"$4);
    end=vma+size;
    if (0x2f4b20 >= vma && 0x2f4b20 < end) printf "0x2f4b20 is in section: %s (vma=0x%x, size=0x%x)\n", name, vma, size;
    if (0x2f4c84 >= vma && 0x2f4c84 < end) printf "0x2f4c84 is in section: %s (vma=0x%x, size=0x%x)\n", name, vma, size;
}'

